let keywords = '';
let count = 5;
let targetAudience = '시니어';
let includeRss = true;
let includeOutlier = true;
try {
  const wh = $('Webhook 수신').all();
  if (wh.length) {
    const raw = wh[0].json;
    const b = raw.body ?? raw;
    const parsed = typeof b === 'string' ? JSON.parse(b) : b;
    if (parsed?.keywords) keywords = String(parsed.keywords);
    if (parsed?.count != null) count = Number(parsed.count) || 5;
    if (parsed?.targetAudience) targetAudience = String(parsed.targetAudience);
    if (parsed?.includeRss != null) includeRss = parsed.includeRss !== false;
    if (parsed?.includeOutlier != null) includeOutlier = parsed.includeOutlier !== false;
  }
} catch {}
if (!Number.isFinite(count) || count < 1) count = 5;
count = Math.min(count, 10);
return [{ json: { keywords, count, targetAudience, includeRss, includeOutlier, source: 'n8n' } }];

const params = $('파라미터 파싱').first().json;
let rssTopics = [];
let outlierTitles = [];
try {
  const rssData = $('RSS 주제 조회').first()?.json;
  rssTopics = (rssData?.topics || []).slice(0, 8).map(t => t.ai_title || t.title).filter(Boolean);
} catch {}
try {
  const outlierData = $('Outlier 영상 조회').first()?.json;
  outlierTitles = (outlierData?.videos || []).slice(0, 8).map(v => v.title).filter(Boolean);
} catch {}


const contextParts = [];
if (rssTopics.length) contextParts.push(`최근 RSS 트렌드 키워드:\n${rssTopics.map((t,i) => `${i+1}. ${t}`).join('\n')}`);
if (outlierTitles.length) contextParts.push(`최근 아웃라이어(히트) 영상 제목:\n${outlierTitles.map((t,i) => `${i+1}. ${t}`).join('\n')}`);
if (params.keywords) contextParts.push(`추가 키워드: ${params.keywords}`);

const contextText = contextParts.length ? contextParts.join('\n\n') : `타겟 오디언스: ${params.targetAudience}`;

const prompt = `당신은 ${params.targetAudience} 타겟 유튜브 채널의 콘텐츠 기획 전문가입니다.\n아래 데이터를 참고해 이번 주 제작할 영상 주제 ${params.count}개를 추천해 주세요.\n\n${contextText}\n\n아래 JSON 배열로만 응답 (다른 텍스트 없이):\n[\n  {\n    "rank": 1,\n    "topic": "주제 키워드 (20자 이내)",\n    "title": "클릭하고 싶은 유튜브 제목 (35자 이내)",\n    "reason": "추천 이유 — 트렌드/아웃라이어/시즌 등 근거 한 문장",\n    "format": "longform 또는 shortform",\n    "urgency": "high 또는 medium 또는 low"\n  }\n]\n\n조건:\n- ${params.targetAudience}이 실제로 검색하거나 공유할 만한 주제\n- 경쟁이 적고 내 채널 강점을 살릴 수 있는 각도\n- 제목은 숫자/구체적 이점 포함 권장`;

return [{ json: {
  ...params,
  geminiPrompt: prompt,
  geminiKey: $env.GEMINI_API_KEY || '',
  rssTopics,
  outlierTitles,
} }];

const params = $('Gemini 프롬프트 구성').first().json;
const geminiRaw = $input.first().json;

let suggestions = [];
try {
  const text = geminiRaw?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const jsonMatch = text.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    suggestions = Array.isArray(parsed) ? parsed : [];
  }
} catch {}

const now = new Date().toISOString();
return [{ json: {
  ok: true,
  mode: 'n8n',
  count: suggestions.length,
  suggestions,
  rssTopics: params.rssTopics || [],
  outlierTitles: params.outlierTitles || [],
  aiEnhanced: suggestions.length > 0,
  aiProvider: 'gemini',
  generatedAt: now,
  message: suggestions.length > 0 ? `주제 ${suggestions.length}개 추천 완료 (Gemini)` : 'Gemini 응답 파싱 실패 — 기본 주제 사용',
} }];

const params = $input.first().json;
const rssTopics = params.rssTopics || [];
const outlierTitles = params.outlierTitles || [];

const fallbackSuggestions = [
  ...rssTopics.slice(0, 3).map((t, i) => ({ rank: i+1, topic: t.slice(0, 20), title: t.slice(0, 35), reason: 'RSS 트렌드 키워드', format: 'longform', urgency: 'medium' })),
  ...outlierTitles.slice(0, 2).map((t, i) => ({ rank: rssTopics.length+i+1, topic: t.slice(0, 20), title: t.slice(0, 35), reason: '아웃라이어 히트 영상 참고', format: 'longform', urgency: 'high' })),
].slice(0, params.count || 5);

return [{ json: {
  ok: true,
  mode: 'fallback',
  count: fallbackSuggestions.length,
  suggestions: fallbackSuggestions,
  rssTopics,
  outlierTitles,
  aiEnhanced: false,
  aiProvider: null,
  generatedAt: new Date().toISOString(),
  message: `GEMINI_API_KEY 미설정 — RSS/Outlier 기반 ${fallbackSuggestions.length}개 기본 추천`,
} }];
